import { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { doc, getDoc } from 'firebase/firestore';
import { db } from '../services/firebase';
import { Activity } from '../types/activity';

export default function ActivityDetails() {
  const { id } = useParams();
  const [activity, setActivity] = useState<Activity | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchActivity = async () => {
      try {
        if (!id) return;
        
        const docRef = doc(db, 'activities', id);
        const docSnap = await getDoc(docRef);
        
        if (docSnap.exists()) {
          setActivity({
            id: docSnap.id,
            ...docSnap.data()
          } as Activity);
        }
      } catch (error) {
        console.error('Error fetching activity: ', error);
      } finally {
        setLoading(false);
      }
    };

    fetchActivity();
  }, [id]);

  if (loading) return <div>Загрузка...</div>;
  if (!activity) return <div>Активность не найдена</div>;

  return (
    <div className="activity-details">
      <h1>{activity.title}</h1>
      <p>{activity.description}</p>
      <div className="details-meta">
        <p><strong>Дата:</strong> {new Date(activity.date).toLocaleString()}</p>
        <p><strong>Место:</strong> {activity.location}</p>
        <p><strong>Участники:</strong> {activity.people.length}/{activity.maxPeople}</p>
      </div>
    </div>
  );
}
